use std::path::{Path, PathBuf};

use serde::Deserialize;
use thiserror::Error;

pub const PACKAGE_MANIFEST_SCHEMA_VERSION: u64 = 1;

fn legacy_package_manifest_schema() -> u64 {
    PACKAGE_MANIFEST_SCHEMA_VERSION
}

#[derive(Debug, Error)]
pub enum ManifestError {
    #[error("manifest io error: {0}")]
    Io(#[from] std::io::Error),

    #[error("manifest parse error: {path}: {msg}")]
    Parse { path: String, msg: String },

    #[error("manifest invalid: {path}: {msg}")]
    Invalid { path: String, msg: String },
}

#[derive(Debug, Clone, Deserialize)]
pub struct PackageManifest {
    /// Missing `schema` is the documented pre-schema form of schema 1.
    #[serde(default = "legacy_package_manifest_schema")]
    pub schema: u64,
    pub name: String,
    pub version: String,
    pub modules: Vec<ModuleEntry>,

    #[serde(default)]
    pub dependencies: Vec<DepEntry>,

    pub obligations: Vec<String>,

    #[serde(default)]
    pub tests: Vec<String>,

    #[serde(default)]
    pub property_tests: Vec<String>,

    pub caps_policy: Option<String>,

    #[serde(default)]
    pub limits: Limits,

    #[serde(default)]
    pub budgets: Budgets,

    #[serde(default)]
    pub property: PropertyConfig,

    #[serde(default)]
    pub gfx: GfxConfig,
}

#[derive(Debug, Clone, Deserialize, Default)]
pub struct Limits {
    /// Kernel evaluation step limit for package evaluation and tests.
    ///
    /// If omitted, the toolchain default is used.
    pub step_limit: Option<u64>,

    /// Allow disabling the step limit via CLI (`--no-step-limit`).
    ///
    /// Default is deny (false).
    #[serde(default)]
    pub allow_unlimited: bool,

    /// Maximum total number of `pair/cons` cells allocated during evaluation.
    pub max_pair_cells: Option<u64>,

    /// Maximum observed vector length (vector literals and `vec/push`).
    pub max_vec_len: Option<u64>,

    /// Maximum observed map length (map literals, `map/put`, `map/merge`).
    pub max_map_len: Option<u64>,

    /// Maximum observed bytes length (bytes literals and `bytes/concat`).
    pub max_bytes_len: Option<u64>,

    /// Maximum observed string length in UTF-8 bytes (string literals and `str/concat`).
    pub max_string_len: Option<u64>,
}

#[derive(Debug, Clone, Deserialize, Default)]
pub struct Budgets {
    /// If set, each unit test must complete within this many kernel evaluation steps.
    pub max_steps_per_test: Option<u64>,

    /// If set, each effectful test must produce no more than this many effect log entries.
    pub max_effect_entries_per_test: Option<u64>,

    /// If set, each effect log must serialize to at most this many bytes in canonical CoreForm.
    pub max_effect_log_bytes_per_test: Option<u64>,
}

#[derive(Debug, Clone, Deserialize, Default)]
pub struct PropertyConfig {
    /// Default number of cases per property test, if the test entry does not specify `:cases`.
    pub cases_per_test: Option<u64>,
}

#[derive(Debug, Clone, Deserialize, Default)]
pub struct GfxConfig {
    /// Suite symbols containing golden frame/scene checks.
    ///
    /// Each suite must evaluate to a map of test-name -> test-entry where test-entry is:
    /// `{ :body <callable> :kind :frame-graph|:scene :expect-h "<hex32>" }`
    #[serde(default)]
    pub golden_tests: Vec<String>,

    /// Suite symbols containing frame budget checks.
    ///
    /// Each suite evaluates to a map of test-name -> test-entry where test-entry is either
    /// a callable body or `{ :body <callable> }`. The body must return a frame-graph term, or
    /// `{ :frame <frame-graph> :frame-time-ms <int> }`.
    #[serde(default)]
    pub frame_budget_tests: Vec<String>,

    /// Optional strict expected list of public gfx exports.
    #[serde(default)]
    pub api_exports: Vec<String>,

    /// Optional expected hash of the public gfx API surface.
    ///
    /// The surface hash is computed from exported symbols + canonical hashes of their defining
    /// CoreForm expressions.
    pub api_surface_hash: Option<String>,

    /// Optional frame budget limits (applied per frame-budget test).
    pub max_render_passes_per_frame: Option<u64>,
    pub max_compute_passes_per_frame: Option<u64>,
    pub max_draw_commands_per_frame: Option<u64>,
    pub max_compute_commands_per_frame: Option<u64>,
    pub max_frame_graph_bytes: Option<u64>,
    pub max_frame_time_ms: Option<u64>,
}

#[derive(Debug, Clone, Deserialize)]
pub struct ModuleEntry {
    pub path: String,
    pub hash: Option<String>,
}

#[derive(Debug, Clone, Deserialize)]
pub struct DepEntry {
    pub name: String,
    pub path: String,
    pub hash: Option<String>,
}

impl PackageManifest {
    pub fn load(path: &Path) -> Result<(Self, PathBuf), ManifestError> {
        let s = std::fs::read_to_string(path)?;
        let m: PackageManifest = toml::from_str(&s).map_err(|e| ManifestError::Parse {
            path: path.display().to_string(),
            msg: e.to_string(),
        })?;
        if m.schema != PACKAGE_MANIFEST_SCHEMA_VERSION {
            return Err(ManifestError::Invalid {
                path: path.display().to_string(),
                msg: format!(
                    "unsupported package manifest schema {} (expected {})",
                    m.schema, PACKAGE_MANIFEST_SCHEMA_VERSION
                ),
            });
        }
        validate_manifest_paths(path, &m)?;
        let dir = path
            .parent()
            .map(PathBuf::from)
            .ok_or_else(|| ManifestError::Invalid {
                path: path.display().to_string(),
                msg: "package.toml has no parent dir".to_string(),
            })?;
        Ok((m, dir))
    }
}

fn validate_manifest_paths(pkg_toml: &Path, m: &PackageManifest) -> Result<(), ManifestError> {
    for (i, me) in m.modules.iter().enumerate() {
        validate_rel_path_str(&me.path, &format!("modules[{i}].path"), pkg_toml)?;
    }
    for (i, de) in m.dependencies.iter().enumerate() {
        validate_rel_path_str(&de.path, &format!("dependencies[{i}].path"), pkg_toml)?;
    }
    if let Some(p) = &m.caps_policy {
        validate_rel_path_str(p, "caps_policy", pkg_toml)?;
    }
    Ok(())
}

fn validate_rel_path_str(s: &str, field: &str, pkg_toml: &Path) -> Result<(), ManifestError> {
    let pstr = pkg_toml.display().to_string();
    if s.is_empty() {
        return Err(ManifestError::Invalid {
            path: pstr,
            msg: format!("{field} must be non-empty"),
        });
    }
    if s.contains('\\') {
        return Err(ManifestError::Invalid {
            path: pstr,
            msg: format!("{field} must use '/' path separators (got backslash)"),
        });
    }
    let p = Path::new(s);
    if p.is_absolute() {
        return Err(ManifestError::Invalid {
            path: pstr,
            msg: format!("{field} must be a relative path, got {s}"),
        });
    }
    for c in p.components() {
        match c {
            std::path::Component::Normal(_) => {}
            // Disallow '.', '..', Windows prefixes, and root dirs to avoid non-portable and unsafe paths.
            _ => {
                return Err(ManifestError::Invalid {
                    path: pstr,
                    msg: format!(
                        "{field} must not contain '.', '..', or absolute/prefix components: {s}"
                    ),
                });
            }
        }
    }
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::{PACKAGE_MANIFEST_SCHEMA_VERSION, PackageManifest};

    fn write_minimal_manifest(path: &std::path::Path, schema: Option<u64>) {
        let schema = schema
            .map(|value| format!("schema = {value}\n"))
            .unwrap_or_default();
        std::fs::write(
            path,
            format!("{schema}name = \"x\"\nversion = \"0.0.1\"\nmodules = []\nobligations = []\n"),
        )
        .unwrap();
    }

    #[test]
    fn schema_one_and_documented_pre_schema_form_are_supported() {
        let td = tempfile::tempdir().unwrap();
        let pkg = td.path().join("package.toml");
        for schema in [None, Some(PACKAGE_MANIFEST_SCHEMA_VERSION)] {
            write_minimal_manifest(&pkg, schema);
            assert_eq!(
                PackageManifest::load(&pkg).unwrap().0.schema,
                PACKAGE_MANIFEST_SCHEMA_VERSION
            );
        }
    }

    #[test]
    fn future_schema_is_rejected() {
        let td = tempfile::tempdir().unwrap();
        let pkg = td.path().join("package.toml");
        write_minimal_manifest(&pkg, Some(PACKAGE_MANIFEST_SCHEMA_VERSION + 1));
        let error = PackageManifest::load(&pkg).unwrap_err().to_string();
        assert!(
            error.contains("unsupported package manifest schema"),
            "{error}"
        );
    }

    #[test]
    fn rejects_parent_dir_in_module_path() {
        let td = tempfile::tempdir().unwrap();
        let pkg = td.path().join("package.toml");
        std::fs::write(
            &pkg,
            r#"
name = "x"
version = "0.0.1"
obligations = []
dependencies = []

[[modules]]
path = "../escape.gc"
hash = ""
"#,
        )
        .unwrap();

        let e = PackageManifest::load(&pkg).unwrap_err();
        let s = format!("{e}");
        assert!(s.contains("must not contain"), "{s}");
    }
}
        },
    );
